class Solution {
    public boolean isRationalEqual(String s, String t) {
        return normalize(s).equals(normalize(t));
    }

    private String normalize(String s) {
        int i = s.indexOf('(');
        if (i != -1) {
            String repeating = s.substring(i + 1, s.length() - 1);
            s = s.substring(0, i) + repeating.repeat(20);
        }
        while (s.length() > 10 && s.charAt(s.length() - 1) == '0') {
            s = s.substring(0, s.length() - 1);
        }
        if (s.endsWith(".")) {
            s = s.substring(0, s.length() - 1);
        }
        return s;
    }
}
